var e=[{id:`L3_1`,type:`dialog`,speaker:`NIGHTMARE_DREAM_NULL_NULL`,text:{KOREA:`아아…….`,JPN:`ああ……`,ENG:`Ahh...`,TWN:`呼呼……`},stage:{bg:`DORMITORY_2`,bgm:`CUTSCENE_TALK_02`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`NIGHTMARE_DREAM_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_IDLE`}}}},{id:`L4_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`깼어? 안색이 어째 안 좋아 보이는데, 괜찮아?`,JPN:`起きた？　なんだか顔色悪そうだけど、大丈夫？`,ENG:`You’re awake. But you don’t look so good. You okay?`,TWN:`醒啦？你臉色不太好？沒事吧？`},stage:{bg:`DORMITORY_2`,bgm:`CUTSCENE_TALK_02`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`NIGHTMARE_DREAM_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L5_1`,type:`dialog`,speaker:`NIGHTMARE_DREAM_NULL_NULL`,text:{KOREA:`글린… 다…….`,JPN:`グリン……ダ……`,ENG:`Glin... da...`,TWN:`格琳…達……`},stage:{bg:`DORMITORY_2`,bgm:`CUTSCENE_TALK_02`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`NIGHTMARE_DREAM_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L8_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`루, 루루?! 뭐야! 정신 차려 봐!`,JPN:`ル、ルル！？　なに！　しっかりして！`,ENG:`L-Lulu?! Hey! Wake up!`,TWN:`露…露露？！怎麼搞的？你振作一點！`},stage:{bg:`DORMITORY_2`,bgm:`CUTSCENE_TALK_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`HERON_NPC_HAVEN_NULL`,text:{KOREA:`으음…….`,JPN:`うーん……`,ENG:`Mmm...`,TWN:`呃嗯……`},stage:{bg:`DORMITORY_2`,bgm:`CUTSCENE_TALK_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HERON_NPC_HAVEN_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`HERON_NPC_HAVEN_NULL`,text:{KOREA:`시끄럽네. 머리 울려…….`,JPN:`うるさいねぇ。頭がガンガンする……`,ENG:`Ugh, my head... What’s all that ruckus?`,TWN:`好吵，頭好痛……`},stage:{bg:`DORMITORY_2`,bgm:`CUTSCENE_TALK_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HERON_NPC_HAVEN_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`루루! 얘가 왜 이러지? 오늘 너무 무리시켰나……?`,JPN:`ルル！　どうしたの？　今日は無理させすぎたのかな……？`,ENG:`Lulu! What’s wrong with her? Did I push her too hard...?`,TWN:`露露！她怎麼會這樣？是今天太累嗎……？`},stage:{bg:`DORMITORY_2`,bgm:`CUTSCENE_TALK_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`정신 좀 차려 봐! 루루!!`,JPN:`ちょっとしっかりしてよ！　ルル！`,ENG:`C’mon Lulu! Wake up!!`,TWN:`露露！！你醒醒！`},stage:{bg:`DORMITORY_2`,bgm:`CUTSCENE_TALK_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`HERON_NPC_HAVEN_NULL`,text:{KOREA:`휴. 기대했건만. 별로 달라진 것도 없는 것 같고…….`,JPN:`ふう。楽しみにしてたのに。あまり変わらないみたいね……`,ENG:`*Sigh...* I had high expectations... But nothing feels like has changed...`,TWN:`哀，我原本還很期待的，結果好像沒什麼用……`},stage:{bg:`DORMITORY_2`,bgm:`CUTSCENE_TALK_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HERON_NPC_HAVEN_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`HERON_NPC_HAVEN_NULL`,text:{KOREA:`저 쪽도…… 뭐 제대로 하지도 못하고 쓰러진 것 같은데.`,JPN:`あちらも……まあ、何もできずに倒れたみたいだし。`,ENG:`And she... Well, it looks like she fainted before she could really do anything.`,TWN:`而且……她好像還沒完成就暈過去了。`},stage:{bg:`DORMITORY_2`,bgm:`CUTSCENE_TALK_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HERON_NPC_HAVEN_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`HERON_NPC_HAVEN_NULL`,text:{KOREA:`……조금 실망스럽네. 더 볼 것도 없겠어.`,JPN:`……ちょっとガッカリ。まあこんなところかしらね。`,ENG:`How disappointing... I guess there’s nothing more to see here.`,TWN:`……真是失望，再待下去也沒意思。`},stage:{bg:`DORMITORY_2`,bgm:`CUTSCENE_TALK_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HERON_NPC_HAVEN_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`NEWCOMER_NPC_DREAM_NULL`,text:{KOREA:`루루……!!`,JPN:`ルル……！！`,ENG:`Lulu...!!`,TWN:`露露……！！`},stage:{bg:`DORMITORY_2`,bgm:`CUTSCENE_TALK_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`NEWCOMER_NPC_DREAM_NULL`,face:`UNIT_SURPRISE`},R:null}}}];export{e as default};